def search_around_amk_with_root(root, window=80, limit=20):
    results=[]
    for h in data:
        text = (h.get('hadithTxt') or '') + '\n' + (h.get('Matn') or '')
        for m in re.finditer(r'(^|[\s\W])أمك([\s\W]|$)', text):
            start = max(0, m.start()-window)
            end = min(len(text), m.end()+window)
            snippet = text[start:end]
            if re.search(root, snippet):
                results.append((h['hadithID'], snippet))
                if len(results)>=limit:
                    return results
    return results

