def search_phrase_around(word, root, window=80):
    res=[]
    for h in data:
        t = (h.get('hadithTxt') or '') + '\n' + (h.get('Matn') or '')
        for m in re.finditer(re.escape(word), t):
            start = max(0, m.start()-window)
            end = min(len(t), m.end()+window)
            snippet = t[start:end]
            if re.search(root, snippet):
                res.append((h['hadithID'], snippet))
                break
    return res

