def search_literal(s):
    res=[]
    for h in data:
        t = (h.get('hadithTxt') or '') + '\n' + (h.get('Matn') or '')
        if s in t:
            res.append((h['hadithID'], t[t.find(s)-50: t.find(s)+len(s)+50]))
    return res

